    const _fn: _HFn = handler;
    const _Ctx = struct {
        conn: std.Io.net.Stream,
        handler_fn: _HFn,
        fn run(ctx: *@This()) void {
            defer std.heap.page_allocator.destroy(ctx);
            defer ctx.conn.close(_io);
            const _alloc = std.heap.page_allocator;
